const perenual = $input.first().json;
const plantName = $('Perenual Search').first().json.data?.[0]?.common_name || '';

const entry = {
  id: plantName.toLowerCase().replace(/\s+/g, '-'),
  name: {
    common: perenual.common_name || plantName,
    scientific: perenual.scientific_name?.[0] || '',
    aliases: perenual.other_name || []
  },
  care: {
    light: {
      type: perenual.sunlight?.[0] || 'medium',
      description: { en: (perenual.sunlight || []).join(', '), es: '' }
    },
    watering: {
      frequency: perenual.watering || 'regular',
      description: { en: perenual.watering || '', es: '' }
    },
    toxicity: {
      pets: perenual.poisonous_to_pets === 1,
      humans: perenual.poisonous_to_humans === 1,
      severity: perenual.poisonous_to_pets === 1 ? 'moderate' : 'none'
    }
  },
  source: 'perenual'
};

return [{ json: entry }];
